# Extract LastPass pricing from the API
python3 -c "
import json
with open('/tmp/lastpass_catalog.json', 'r') as f:
    data = json.load(f)

for product in data['productsWithPrices']:
    sku = product['product']['productSku']
    name = product['product']['productName']
    for price in product['productPrices']:
        if price['currency'] == 'USD':
            for level in price['productPriceLevels']:
                print(f'{sku}: {name} - {price[\"paymentPlanId\"]} - \${level[\"price\"]}/year')
"
